  // Redirect based on user role
  if (user && location === "/") {
    const redirectPath = user.role === "Vendor" ? "/vendor-portal" :
                        user.role === "Merchant" ? "/merchant-portal" :
                        user.role === "Tenant" ? "/tenant/home" : "/dashboard";
    return <Redirect to={redirectPath} />;
