                  </div>
                  <div className="space-y-1">
                    <p className="text-sm font-medium">Emergency</p>
                    <div className="flex items-center gap-2 flex-wrap text-sm text-muted-foreground">
                      <Phone className="h-3 w-3" />
                      (555) 999-0000
                    </div>
                  </div>
                </div>
                <Button variant="outline" className="w-full" data-testid="button-submit-ticket">
                  <MessageSquare className="h-4 w-4 mr-2" />
                  Submit Support Ticket
                </Button>
              </CardContent>
            </Card>
          </div>
        </TabsContent>
      </Tabs>

      <Dialog open={settlementOpen} onOpenChange={setSettlementOpen}>
        <DialogContent className="sm:max-w-[500px]">
          <DialogHeader>
            <DialogTitle>Initiate Settlement</DialogTitle>
            <DialogDescription>
              Settle your pending USD balance to your bank account
            </DialogDescription>
          </DialogHeader>
          <div className="space-y-6 py-4">
            <div className="space-y-2">
              <Label htmlFor="settlement-amount-quick">Amount (USD)</Label>
              <Input
                id="settlement-amount-quick"
                type="number"
                placeholder="0.00"
                value={settlementAmount}
                onChange={(e) => setSettlementAmount(e.target.value)}
                min="0"
                max={totalPending}
                step="0.01"
                data-testid="input-settlement-amount-quick"
              />
              <p className="text-sm text-muted-foreground">
                Available for settlement: ${formatCurrency(totalPending)}
              </p>
            </div>
            <div className="space-y-3">
              <Label>Payment Method</Label>
              <RadioGroup value={paymentMethod} onValueChange={(value: any) => setPaymentMethod(value)}>
                <div className="flex items-start space-x-3 p-4 border rounded-md cursor-pointer hover-elevate" onClick={() => setPaymentMethod("ach")}>
                  <RadioGroupItem value="ach" id="ach-quick" data-testid="radio-ach-quick" />
                  <div className="flex-1">
                    <Label htmlFor="ach-quick" className="cursor-pointer font-medium">ACH Transfer</Label>
                    <p className="text-sm text-muted-foreground">Standard bank transfer - 1-2 business days - No fee</p>
                  </div>
                </div>
                <div className="flex items-start space-x-3 p-4 border rounded-md cursor-pointer hover-elevate" onClick={() => setPaymentMethod("wire")}>
                  <RadioGroupItem value="wire" id="wire-quick" data-testid="radio-wire-quick" />
                  <div className="flex-1">
                    <Label htmlFor="wire-quick" className="cursor-pointer font-medium">Wire Transfer</Label>
                    <p className="text-sm text-muted-foreground">Same-day transfer - $25 fee</p>
                  </div>
                </div>
              </RadioGroup>
            </div>
            {settlementAmount && parseFloat(settlementAmount) > 0 && (
              <div className="p-4 bg-muted rounded-md space-y-2">
                <div className="flex justify-between gap-2 text-sm flex-wrap">
                  <span>Settlement Amount:</span>
                  <span className="font-mono font-semibold">${parseFloat(settlementAmount).toFixed(2)}</span>
                </div>
                <div className="flex justify-between gap-2 text-sm flex-wrap">
                  <span>Fee:</span>
                  <span className="font-mono">${paymentMethod === "wire" ? "25.00" : "0.00"}</span>
                </div>
                <div className="flex justify-between gap-2 text-sm border-t pt-2 flex-wrap">
                  <span className="font-medium">Net Amount:</span>
                  <span className="font-mono font-bold text-green-600 dark:text-green-400">
                    ${(parseFloat(settlementAmount) - (paymentMethod === "wire" ? 25 : 0)).toFixed(2)}
                  </span>
                </div>
              </div>
            )}
            <Button
              onClick={handleSettlement}
              className="w-full"
              disabled={settlementMutation.isPending}
              data-testid="button-confirm-settlement-quick"
            >
              {settlementMutation.isPending ? "Processing..." : "Confirm Settlement"}
            </Button>
          </div>
        </DialogContent>
      </Dialog>
    </div>
  );
}

client/src/pages/merchant-login.tsx.content:
import { useState } from "react";
import { useLocation } from "wouter";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { useToast } from "@/hooks/use-toast";
import { useAuth } from "@/lib/auth-context";
import { apiRequest } from "@/lib/queryClient";
import { Store, Loader2, ArrowLeft } from "lucide-react";
import { Link } from "wouter";

export default function MerchantLogin() {
  const [, setLocation] = useLocation();
  const { setAuth } = useAuth();
  const { toast } = useToast();
  const [loading, setLoading] = useState(false);
  const [email, setEmail] = useState("");
  const [code, setCode] = useState("");
  const [codeSent, setCodeSent] = useState(false);

  const handleSendCode = async () => {
    if (!email) {
      toast({
        title: "Email Required",
        description: "Please enter your email address.",
        variant: "destructive",
      });
      return;
    }

    setLoading(true);
    try {
      await apiRequest("POST", "/api/merchant-auth/send-code", { email });
      setCodeSent(true);
      toast({
        title: "Magic Code Sent",
        description: "Check your email for the 6-digit code.",
      });
    } catch (error: any) {
      toast({
        title: "Error",
        description: error.message || "Failed to send magic code. Are you registered as a merchant?",
        variant: "destructive",
      });
    } finally {
      setLoading(false);
    }
  };

  const handleLogin = async () => {
    if (!code) {
      toast({
        title: "Code Required",
        description: "Please enter the 6-digit magic code.",
        variant: "destructive",
      });
      return;
    }

    setLoading(true);
    try {
      const response = await apiRequest("POST", "/api/merchant-auth/login", {
        email,
        code,
      });

      setAuth(response.user, null);
      toast({
        title: "Welcome Back",
        description: `Logged in as ${response.user.email}`,
      });
      setLocation("/merchant-portal");
    } catch (error: any) {
      toast({
        title: "Login Failed",
        description: error.message || "Invalid magic code or no merchant access.",
        variant: "destructive",
      });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-background p-4">
      <div className="w-full max-w-md">
        <div className="text-center mb-8">
          <div className="inline-flex items-center justify-center w-16 h-16 rounded-2xl bg-primary mb-4">
            <Store className="w-10 h-10 text-primary-foreground" />
          </div>
          <h1 className="text-4xl font-semibold tracking-tight mb-2">Merchant Portal</h1>
          <p className="text-muted-foreground">
            View NUSD settlements, stablecoin backing, and yield orchestration
          </p>
        </div>

        <Card>
          <CardHeader>
            <CardTitle>Merchant Login</CardTitle>
            <CardDescription>
              Enter your registered merchant email to receive a magic link
            </CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="space-y-2">
              <Label htmlFor="email">Email</Label>
              <Input
                id="email"
                type="email"
                placeholder="merchant@store.com"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                disabled={codeSent || loading}
                data-testid="input-merchant-email"
              />
            </div>

            {!codeSent ? (
              <Button 
                onClick={handleSendCode} 
                disabled={loading} 
                className="w-full"
                data-testid="button-send-code"
              >
                {loading ? (
                  <>
                    <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                    Sending...
                  </>
                ) : (
                  "Send Magic Code"
                )}
              </Button>
            ) : (
              <>
                <div className="space-y-2">
                  <Label htmlFor="code">6-Digit Code</Label>
                  <Input
                    id="code"
                    type="text"
                    placeholder="000000"
                    value={code}
                    onChange={(e) => setCode(e.target.value)}
                    disabled={loading}
                    maxLength={6}
                    data-testid="input-magic-code"
                  />
                </div>

                <div className="flex gap-2">
                  <Button
                    variant="outline"
                    onClick={() => {
                      setCodeSent(false);
                      setCode("");
                    }}
                    disabled={loading}
                    className="flex-1"
                    data-testid="button-back"
                  >
                    <ArrowLeft className="mr-2 h-4 w-4" />
                    Back
                  </Button>
                  <Button 
                    onClick={handleLogin} 
                    disabled={loading}
                    className="flex-1"
                    data-testid="button-login"
                  >
                    {loading ? (
                      <>
                        <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                        Logging in...
                      </>
                    ) : (
                      "Login"
                    )}
                  </Button>
                </div>
              </>
            )}

            <div className="pt-4 border-t text-center">
              <p className="text-sm text-muted-foreground mb-2">
                Not a merchant?
              </p>
              <Link href="/">
                <Button variant="ghost" size="sm" data-testid="link-regular-login">
                  Go to Regular Login
                </Button>
              </Link>
            </div>
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

