                <p className="text-sm mt-1" style={{ color: "hsl(var(--tenant-muted-foreground))" }}>Create a split to share costs with neighbors</p>
              </CardContent>
            </Card>
          ) : (
            p2p.splitExpenses.map((split) => (
              <Card
                key={split.id}
                className="border"
                data-testid={`split-card-${split.id}`}
