}

interface TenantScoreDriver {
  factor: string;
  weight: number;
  score: number;
}

interface TenantScore {
  id: string;
  name: string;
  unit: string;
  stabilityScore: number;
  paymentPattern: string;
  spikeEvents: number;
  streakMonths: number;
  tierMigration: string;
