                          backgroundColor: s.color === "success" ? "hsl(var(--tenant-success))" : "hsl(var(--tenant-primary))",
                          color: "white",
                        }}
                      >{s.step}</div>
                      <s.icon className="h-4 w-4" style={{ color: s.color === "success" ? "hsl(var(--tenant-success))" : "hsl(var(--tenant-primary))" }} />
