  const duplicateMutation = useMutation({
    mutationFn: (id: string) => apiRequest("POST", `/api/lease-agreements/${id}/duplicate`),
    onSuccess: (dup: any) => {
      queryClient.invalidateQueries({ queryKey: ["/api/lease-agreements"] });
