                  </CardTitle>
                </CardHeader>
                <CardContent>
                  <div className="space-y-4">
                    {notificationPrefs.map((pref) => (
                      <div key={pref.id} className="flex items-center justify-between gap-3" data-testid={`notif-pref-${pref.id}`}>
