                        <div className="flex items-center gap-2 flex-wrap">
                          {getStatusBadge(insp.status)}
                          <Button variant="ghost" size="icon" data-testid={`button-view-inspection-${insp.id}`}>
                            <Eye className="w-4 h-4" />
                          </Button>
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </CardContent>
            </Card>
