                        <td className="p-3 font-mono tabular-nums font-medium">${d.refund.toLocaleString()}</td>
                        <td className="p-3">
                          <Badge variant={depositStatusVariant[d.status]} className="text-xs" data-testid={`badge-deposit-status-${idx}`}>
