                        <td className="p-3 text-muted-foreground text-xs max-w-[180px] truncate">{d.reason}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </CardContent>
          </Card>
        </TabsContent>
      </Tabs>
    </div>
  );
}

